#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void srad_kernel(
    const float lambda,
    const int rows,
    const int cols,
    const long size_I,
    __global int* iN,
    __global int* iS,
    __global int* jE,
    __global int* jW,
    __global float* dN,
    __global float* dS,
    __global float* dW,
    __global float* dE,
    const float q0sqr,
    __global float* c,
    __global float* J)
{
    int gid = get_global_id(0);

    if (gid < size_I) {
        int i = gid / cols;
        int j = gid % cols;

        float Jc = J[gid];

        float dN_val = J[iN[i] * cols + j] - Jc;
        float dS_val = J[iS[i] * cols + j] - Jc;
        float dW_val = J[i * cols + jW[j]] - Jc;
        float dE_val = J[i * cols + jE[j]] - Jc;

        dN[gid] = dN_val;
        dS[gid] = dS_val;
        dW[gid] = dW_val;
        dE[gid] = dE_val;

        float G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
        float L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        float den = 1.0f + (0.25f * L);
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        c[gid] = c_val;
    }
}

__kernel void srad2_kernel(
    const float lambda,
    const int rows,
    const int cols,
    const long size_I,
    __global int* iN,
    __global int* iS,
    __global int* jE,
    __global int* jW,
    __global float* dN,
    __global float* dS,
    __global float* dW,
    __global float* dE,
    __global float* c,
    __global float* J)
{
    int gid = get_global_id(0);

    if (gid < size_I) {
        int i = gid / cols;
        int j = gid % cols;

        float cN = c[gid];
        float cS = c[iS[i] * cols + j];
        float cW = c[gid];
        float cE = c[i * cols + jE[j]];

        float D = cN * dN[gid] + cS * dS[gid] + cW * dW[gid] + cE * dE[gid];

        J[gid] = J[gid] + 0.25f * lambda * D;
    }
}
